#include <climits>

using namespace std;

long long solve(vector<long long> nums, long long k) {
    long long total_sum = 0;
    for (long long num : nums) {
        total_sum += num;
    }

    long long prefix = 0;
    long long dp_prev = 0;
    unordered_map<long long, long long> max_val;
    max_val[0] = 0;

    for (long long num : nums) {
        prefix += num;
        long long mod = prefix % k;
        long long current_max = (max_val.find(mod) != max_val.end()) ? max_val[mod] : LLONG_MIN;
        long long dp_current = max(dp_prev, prefix + current_max);
        long long new_val = dp_current - prefix;
        if (max_val.find(mod) != max_val.end()) {
            if (new_val > max_val[mod]) {
                max_val[mod] = new_val;
            }
        } else {
            max_val[mod] = new_val;
        }
        dp_prev = dp_current;
    }

    return total_sum - dp_prev;
}
